import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import MapView from '../components/MapView';
import './HomePage.css';

function isValidIP(ip) {
  const ipv4 = /^(\d{1,3}\.){3}\d{1,3}$/;
  const ipv6  = /^([0-9a-fA-F]{0,4}:){2,7}[0-9a-fA-F]{0,4}$/;
  if (ipv4.test(ip)) {
    return ip.split('.').every(n => parseInt(n) <= 255);
  }
  return ipv6.test(ip);
}

export default function HomePage() {
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem('user') || '{}');

  const [geoData,   setGeoData]   = useState(null);
  const [myGeoData, setMyGeoData] = useState(null);
  const [searchIP,  setSearchIP]  = useState('');
  const [loading,   setLoading]   = useState(false);
  const [ipError,   setIpError]   = useState('');
  const [history,   setHistory]   = useState(() => {
    try { return JSON.parse(localStorage.getItem('ip_history') || '[]'); }
    catch { return []; }
  });
  const [selected, setSelected] = useState([]);

  useEffect(() => {
    localStorage.setItem('ip_history', JSON.stringify(history));
  }, [history]);

  const fetchMyIP = useCallback(async () => {
    setLoading(true);
    try {
      const res  = await fetch('https://ipinfo.io/geo');
      const data = await res.json();
      setMyGeoData(data);
      setGeoData(data);
    } catch {
      setIpError('Could not fetch your IP information.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchMyIP(); }, [fetchMyIP]);

  async function fetchGeoForIP(ip) {
    setLoading(true);
    setIpError('');
    try {
      const res  = await fetch(`https://ipinfo.io/${ip}/geo`);
      const data = await res.json();
      if (data.bogon) {
        setIpError('This is a private/reserved IP address with no geolocation.');
        return null;
      }
      return data;
    } catch {
      setIpError('Failed to fetch geolocation data.');
      return null;
    } finally {
      setLoading(false);
    }
  }

  async function handleSearch(e) {
    e.preventDefault();
    const ip = searchIP.trim();
    if (!ip) {
      setIpError('Please enter an IP address.');
      return;
    }
    if (!isValidIP(ip)) {
      setIpError('Invalid IP address format. Please enter a valid IPv4 or IPv6 address.');
      return;
    }
    const data = await fetchGeoForIP(ip);
    if (!data) return;
    setGeoData(data);
    setHistory(prev => {
      const exists = prev.find(h => h.ip === ip);
      if (exists) return prev;
      return [{ ip, data, searchedAt: new Date().toLocaleString() }, ...prev];
    });
  }

  function handleClear() {
    setSearchIP('');
    setIpError('');
    setGeoData(myGeoData);
  }

  function handleHistoryClick(item) {
    setGeoData(item.data);
    setSearchIP(item.ip);
    setIpError('');
  }

  function toggleSelect(ip) {
    setSelected(prev =>
      prev.includes(ip) ? prev.filter(x => x !== ip) : [...prev, ip]
    );
  }

  function deleteSelected() {
    setHistory(prev => prev.filter(h => !selected.includes(h.ip)));
    setSelected([]);
  }

  function handleLogout() {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  }

  function parseCoords(loc) {
    if (!loc) return null;
    const parts = loc.split(',');
    if (parts.length !== 2) return null;
    const lat = parseFloat(parts[0]);
    const lng = parseFloat(parts[1]);
    if (isNaN(lat) || isNaN(lng)) return null;
    return [lat, lng];
  }

  const coords = geoData ? parseCoords(geoData.loc) : null;

  return (
    <div className="home-page">
      <nav className="navbar">
        <div className="nav-brand">🌐 IP Geolocation</div>
        <div className="nav-user">
          <span>👤 {user.name || user.email}</span>
          <button className="btn btn-ghost" onClick={handleLogout}>Logout</button>
        </div>
      </nav>

      <div className="home-container">
        <div className="card search-card">
          <h2>Look up an IP address</h2>
          <form className="search-form" onSubmit={handleSearch}>
            <input
              type="text"
              placeholder="Enter IP address (e.g. 8.8.8.8)"
              value={searchIP}
              onChange={e => { setSearchIP(e.target.value); setIpError(''); }}
              className={ipError ? 'error' : ''}
            />
            <button type="submit" className="btn btn-primary" disabled={loading}>
              {loading ? '…' : '🔍 Search'}
            </button>
            {searchIP && (
              <button type="button" className="btn btn-ghost" onClick={handleClear}>
                ✕ Clear
              </button>
            )}
          </form>
          {ipError && <p className="error-msg" style={{ marginTop: 8 }}>⚠️ {ipError}</p>}
        </div>

        <div className="main-grid">
          <div className="left-col">
            {loading && !geoData && (
              <div className="card loading-card">⏳ Fetching IP information…</div>
            )}

            {geoData && (
              <div className="card geo-card">
                <div className="geo-header">
                  <span className="geo-badge">
                    {geoData.ip === myGeoData?.ip ? '📍 Your IP' : '🔎 Searched IP'}
                  </span>
                  <h3>{geoData.ip}</h3>
                </div>
                <div className="geo-grid">
                  <GeoRow icon="🏙️" label="City"        value={geoData.city}     />
                  <GeoRow icon="🗺️" label="Region"      value={geoData.region}   />
                  <GeoRow icon="🌍" label="Country"     value={geoData.country}  />
                  <GeoRow icon="📮" label="Postal"      value={geoData.postal}   />
                  <GeoRow icon="🏢" label="Org / ISP"   value={geoData.org}      />
                  <GeoRow icon="⏰" label="Timezone"    value={geoData.timezone} />
                  <GeoRow icon="📌" label="Coordinates" value={geoData.loc}      />
                </div>
              </div>
            )}

            {coords && (
              <div className="card" style={{ padding: 0, overflow: 'hidden', marginTop: 16 }}>
                <MapView
                  coords={coords}
                  label={`${geoData.city || ''}, ${geoData.country || ''} (${geoData.ip})`}
                />
              </div>
            )}
          </div>

          <div className="right-col">
            <div className="card history-card">
              <div className="history-header">
                <h3>🕓 Search History</h3>
                {selected.length > 0 && (
                  <button className="btn btn-danger" onClick={deleteSelected}>
                    🗑️ Delete ({selected.length})
                  </button>
                )}
              </div>

              {history.length === 0 ? (
                <p className="history-empty">No searches yet. Try looking up an IP above!</p>
              ) : (
                <ul className="history-list">
                  {history.map(item => (
                    <li
                      key={item.ip}
                      className={`history-item ${selected.includes(item.ip) ? 'selected' : ''}`}
                    >
                      <input
                        type="checkbox"
                        checked={selected.includes(item.ip)}
                        onChange={() => toggleSelect(item.ip)}
                        onClick={e => e.stopPropagation()}
                      />
                      <div className="history-info" onClick={() => handleHistoryClick(item)}>
                        <span className="history-ip">{item.ip}</span>
                        <span className="history-location">
                          {[item.data.city, item.data.region, item.data.country]
                            .filter(Boolean).join(', ')}
                        </span>
                        <span className="history-time">{item.searchedAt}</span>
                      </div>
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

function GeoRow({ icon, label, value }) {
  if (!value) return null;
  return (
    <div className="geo-row">
      <span className="geo-icon">{icon}</span>
      <span className="geo-label">{label}</span>
      <span className="geo-value">{value}</span>
    </div>
  );
}
